import sys

def nth_good_integer(N):
    # Map base-5 digits to even digits
    mapping = {0: '0', 1: '2', 2: '4', 3: '6', 4: '8'}

    # Convert N-1 to base-5 as a string
    if N == 0:
        return '0'
    num = N - 1
    result = ''
    while num > 0:
        remainder = num % 5
        result = mapping[remainder] + result
        num = num // 5
    return result

def main():
    N = int(sys.stdin.read())
    print(nth_good_integer(N))

if __name__ == "__main__":
    main()
